const foobarHorizontalLinePath = `M 7.500000,4.276816 L 2.475141,4.276816 C 2.466557,4.383637 2.433263,4.408304 2.431506,4.407243 C 2.429749,4.406182 2.285104,4.301137 2.255776,4.301137 C 2.226686,4.301137 2.176136,4.301137 2.128925,4.301137 C 2.081714,4.301137 2.064482,4.459530 2.063831,4.461130 L 1.482752,4.226028 L 2.063831,3.990926 C 2.064482,3.992526 2.081714,4.150920 2.128925,4.150920 C 2.176136,4.150920 2.226447,4.150920 2.255776,4.150920 C 2.285104,4.150920 2.431070,4.043509 2.431506,4.044814 C 2.431942,4.046118 2.466557,4.068419 2.475141,4.175241 L 7.500000,4.175241 L 12.524860,4.175279 C 12.533445,4.068458 12.568059,4.046157 12.568495,4.044853 C 12.568932,4.043548 12.714897,4.150960 12.744225,4.150960 C 12.773553,4.150960 12.823864,4.150960 12.871075,4.150961 C 12.918286,4.150961 12.935520,3.992568 12.936171,3.990968 L 13.517248,4.226074 L 12.936167,4.461172 C 12.935516,4.459572 12.918285,4.301179 12.871074,4.301178 C 12.823863,4.301178 12.773314,4.301177 12.744224,4.301177 C 12.714896,4.301177 12.570250,4.406221 12.568493,4.407282 C 12.566735,4.408343 12.533442,4.383676 12.524859,4.276855 L 7.500000,4.276816`

func drawFoobarTextAndLines(
	builder *svgutils.SVGBuilder,
	width float64,
	height float64,
	outerBounds canvas.Rect,
	foregroundColor string,
	lines []string,
	strokeOnly bool,
) {
	fontFamily := canvas.NewFontFamily("Limelight")
	if err := fontFamily.LoadFont(fonts.Limelight, 0, canvas.FontRegular); err != nil {
		log.Println("Failed to load Limelight font: ", err)
		panic("Font loading error")
	}

	numLines := len(lines)
	if numLines == 0 {
		return
	}

	const topPadding = 2.0
	const bottomPadding = 2.0
	const lineSpacing = 0.5
	availableHeight := height - (topPadding + bottomPadding) - float64(numLines-1)*lineSpacing

	var containerHeights []float64
	switch numLines {
	case 3:
		containerHeights = []float64{
			availableHeight * 0.25,
			availableHeight * 0.5,
			availableHeight * 0.25,
		}
	case 2:
		containerHeights = []float64{
			availableHeight * 0.6,
			availableHeight * 0.4,
		}
	default:
		containerHeights = []float64{availableHeight}
	}

	// Parse horizontal line path once to check it's valid.
	_, lineErr := canvas.ParseSVGPath(foobarHorizontalLinePath)

	currentY := height - topPadding

	for i, line := range lines {
		containerHeight := containerHeights[i]
		container := canvas.Rectangle(width-2.5, containerHeight)
		containerBounds := container.Bounds()
		containerX := width/2 - containerBounds.W()/2
		containerY := currentY - containerHeight

		// Draw horizontal line in the gap above this block - use same transform as container.
		// Parse and normalize a fresh path each time (Translate may mutate the path).
		if i > 0 && lineErr == nil {
			linePath, _ := canvas.ParseSVGPath(foobarHorizontalLinePath)
			bounds := linePath.Bounds()
			normCX := (bounds.X0 + bounds.X1) / 2
			normCY := (bounds.Y0 + bounds.Y1) / 2
			linePath = linePath.Translate(-normCX, -normCY)
			gapCenterY := currentY + lineSpacing/2
			centerX := containerX + containerBounds.W()/2
			positionedPath := linePath.Translate(centerX, gapCenterY)
			positionedPath = positionedPath.Scale(1, -1)
			positionedPath = positionedPath.Translate(0, height)
			builder.AddPath(positionedPath.ToSVG(), map[string]string{
				"fill":         map[bool]string{true: "none", false: foregroundColor}[strokeOnly],
				"id":           "deco-path",
				"stroke":       map[bool]string{true: "black", false: "none"}[strokeOnly],
				"stroke-width": "0.025",
			})
		}

		container = container.Translate(containerX, containerY)
		container = container.Scale(1, -1)
		container = container.Translate(0, height)

		builder.AddPath(container.ToSVG(), map[string]string{
			"fill": "none",
			// "stroke": "none",
			"stroke":       "pink",
			"stroke-width": "0.025",
			"id":           fmt.Sprintf("text-container-%d", i),
		})

		fontSize := 20.0
		face := fontFamily.Face(fontSize, canvas.FontRegular, canvas.FontNormal)
		textPath, _, err := face.ToPath(line)
		if err != nil {
			log.Fatalf("Failed to convert text to path: %v", err)
		}
		textBounds := textPath.Bounds()
		scale := min(containerBounds.W()/textBounds.W(), containerBounds.H()/textBounds.H())
		textPath = textPath.Scale(scale, scale)
		textBounds = textPath.Bounds()

		centerX := containerX + containerBounds.W()/2
		centerY := containerY + containerBounds.H()/2
		textCenterX := textBounds.X0 + textBounds.W()/2
		textCenterY := textBounds.Y0 + textBounds.H()/2
		x := centerX - textCenterX
		y := centerY - textCenterY

		textPath = textPath.Translate(x, y)
		textPath = textPath.Scale(1, -1)
		textPath = textPath.Translate(0, height)

		builder.AddPath(textPath.ToSVG(), map[string]string{
			"fill":         map[bool]string{true: "none", false: foregroundColor}[strokeOnly],
			"id":           fmt.Sprintf("text-line-%d", i),
			"stroke":       map[bool]string{true: "black", false: "none"}[strokeOnly],
			"stroke-width": "0.025",
		})

		currentY -= containerHeight + lineSpacing
	}
}

func drawFoobar(
	width float64,
	height float64,
	foregroundColor string,
	backgroundColor string,
	lines []string,
	strokeOnly bool,
) string {
	if strokeOnly {
		foregroundColor = "transparent"
		backgroundColor = "transparent"
	} else {
		foregroundColor = GetColor(foregroundColor)
		backgroundColor = GetColor(backgroundColor)
	}

	builder := svgutils.NewSVGBuilder(width, height)

	outerBounds := drawFoobarShapes(builder, foregroundColor, backgroundColor, strokeOnly)
	drawFoobarTextAndLines(builder, width, height, outerBounds, foregroundColor, lines, strokeOnly)

	builder.EndGroup()

	return builder.Close()
}
